// ── Extract & normalize email fields ──
const email = $input.item.json;

const messageId = (
  email.headers?.['message-id']?.[0] ||
  email.messageId ||
  `fallback-${Date.now()}-${Math.random().toString(36).substr(2,9)}`
).replace(/[<>]/g, '').trim();

const xAutoSubmitted = (email.headers?.['x-auto-submitted']?.[0] || '').toLowerCase();
const autoSubmitted   = (email.headers?.['auto-submitted']?.[0]   || '').toLowerCase();
const precedence      = (email.headers?.['precedence']?.[0]        || '').toLowerCase();

const isAutoReply = xAutoSubmitted.includes('auto') ||
                    autoSubmitted.includes('auto')   ||
                    precedence === 'bulk'             ||
                    precedence === 'junk';

const fromRaw = email.from?.value?.[0] || {};

return {
  json: {
    message_id:   messageId,
    thread_id:    email.headers?.['references']?.[0]?.split(' ')[0] || messageId,
    from_address: fromRaw.address || email.from || '',
    from_name:    fromRaw.name    || '',
    to_addresses: (email.to?.value || []).map(t => t.address),
    subject:      (email.subject || '').trim(),
    body_text:    (email.text || email.textAsHtml || '').slice(0, 8000),
    received_at:  email.date || new Date().toISOString(),
    is_auto_reply: isAutoReply,
    raw_headers:  JSON.stringify(email.headers || {})
  }
};

// ══════════════════════════════════════════════
// SAFETY VALVE — Multi-layer anti-loop guard
// ══════════════════════════════════════════════
const email = $('Extract & Sanitize Email').item.json;
const fromAddr = (email.from_address || '').toLowerCase();
const subject  = (email.subject || '').toLowerCase();
let   headers  = {};
try { headers = JSON.parse(email.raw_headers || '{}'); } catch(e) {}

// Layer 1: Auto-reply headers
const autoHdrKeys = ['x-auto-submitted','auto-submitted','x-autoreply','x-autoresponder'];
const hasAutoHdr  = autoHdrKeys.some(h => headers[h] && !String(headers[h][0]).includes('no'));

// Layer 2: Bot addresses
const botPatterns = ['no-reply@','noreply@','do-not-reply@','donotreply@',
  'mailer-daemon@','postmaster@','bounce@','bounces@','auto-reply@',
  'autoreply@','notifications@','alerts@','support-noreply@'];
const isBotAddr = botPatterns.some(p => fromAddr.includes(p));

// Layer 3: Auto-reply subject
const autoSubjects = ['auto-reply:','automatic reply:','out of office:',
  'autoreply:','[auto]','auto response:','away message:',
  'delivery status:','undeliverable:','failed delivery','mail delivery failed'];
const hasAutoSubj = autoSubjects.some(p => subject.startsWith(p) || subject.includes(p));

// Layer 4: Our own addresses (UPDATE THESE!)
const ourAddresses = ['your-email@gmail.com'];
const isOurAddr = ourAddresses.some(a => fromAddr.includes(a));

// Layer 5: is_auto_reply flag from extraction step
const wasAutoReply = email.is_auto_reply === true;

const isLoop = hasAutoHdr || isBotAddr || hasAutoSubj || isOurAddr || wasAutoReply;
const loopReason = [
  hasAutoHdr   && 'auto_header',
  isBotAddr    && 'bot_address',
  hasAutoSubj  && 'auto_subject_prefix',
  isOurAddr    && 'our_own_address',
  wasAutoReply && 'auto_reply_flag'
].filter(Boolean).join(', ');

return { json: { ...email, is_loop: isLoop, loop_reason: loopReason || 'none' } };

