const raw = $input.item.json;
const emailData = $('Safety Valve — Anti-Loop').item.json;

let parsed;
try {
  const content = raw.choices?.[0]?.message?.content || '{}';
  parsed = JSON.parse(content);
} catch(e) {
  parsed = { category:'inquiry', confidence:0.5, needs_reply:true, sentiment_score:0, reasoning:'json_parse_error' };
}

const usage = raw.usage || {};

return {
  json: {
    ...emailData,
    category:        parsed.category       || 'inquiry',
    confidence:      parseFloat(parsed.confidence) || 0.5,
    needs_reply:     parsed.needs_reply !== false,
    sentiment_score: parseFloat(parsed.sentiment_score) || 0,
    classify_reason: parsed.reasoning      || '',
    token_classify: {
      prompt_tokens:     usage.prompt_tokens     || 0,
      completion_tokens: usage.completion_tokens || 0,
      total_tokens:      usage.total_tokens      || 0
    }
  }
};

const email = $('Parse Classification').item.json;
const threadRows = $input.all();

const historyText = threadRows.length > 0
  ? threadRows.map((r,i) => `[Prior reply ${i+1}] ${r.json.body_text?.slice(0,300) || ''}`).join('\n---\n')
  : 'No prior replies in this thread.';

// Business context — hardcoded summary (matches business_context.json)
// In production: mount the JSON file and read it here
const bizContext = [
  'Company: Your Company Name | Founder: Krishna | Site: yourwebsite.com',
  'Products: Pro ($99/mo), Free (forever, no CC)',
  'Tone: Professional, warm, concise — NEVER more than 150 words',
  'Sign-off: Best regards,\\nKrishna\\nFounder, Your Company Name',
  'Never mention competitors. Never promise unannounced features.',
  'If escalation needed (legal threats, data breach, press): say you will personally follow up.'
].join('\n');

return {
  json: {
    ...email,
    biz_context:   bizContext,
    thread_history: historyText
  }
};

