const raw = $input.item.json;
const emailData = $('Build Draft Prompt').item.json;

let parsed;
try {
  const content = raw.choices?.[0]?.message?.content || '{}';
  parsed = JSON.parse(content);
} catch(e) {
  parsed = {
    draft_subject: 'Re: ' + emailData.subject,
    draft_body: 'Hi,\n\nThank you for reaching out. I will personally review this and get back to you shortly.\n\nBest regards,\nKrishna',
    sentiment_score: 0,
    confidence: 0.3,
    reasoning: 'json_parse_error — used fallback'
  };
}

const usage = raw.usage || {};
const tokenUsage = JSON.stringify({
  classify: emailData.token_classify,
  draft: {
    prompt_tokens:     usage.prompt_tokens     || 0,
    completion_tokens: usage.completion_tokens || 0,
    total_tokens:      usage.total_tokens      || 0
  },
  total_tokens: (emailData.token_classify?.total_tokens || 0) + (usage.total_tokens || 0)
});

return {
  json: {
    ...emailData,
    draft_subject:  parsed.draft_subject  || 'Re: ' + emailData.subject,
    draft_body:     parsed.draft_body     || '',
    draft_reasoning: parsed.reasoning     || '',
    token_usage_str: tokenUsage
  }
};
